package br.com.estacionamento.pagamentos.controller;import br.com.estacionamento.pagamentos.model.Pagamento;import br.com.estacionamento.pagamentos.repository.PagamentoRepository;import br.com.estacionamento.pagamentos.service.PagamentoService;import org.springframework.web.bind.annotation.*;import java.util.*;@RestController @RequestMapping("/api/pagamentos") public class PagamentoController{private final PagamentoRepository repo;private final PagamentoService service;public PagamentoController(PagamentoRepository repo,PagamentoService service){this.repo=repo;this.service=service;}@GetMapping public List<Pagamento> listar(){return repo.findAll();}@PostMapping public Pagamento pagar(@RequestBody Pagamento p){return service.pagar(p);}}
